var COURSE_TR_JA = [{day: 1, title: `Selamlaşma ve Temel Nezaket`, title_native: `あいさつと基本の礼儀`, focus: `Tokyo’ya yeni vardığında insanlarla kibarca selamlaşmayı ve basit teşekkür ifadelerini kullanmayı öğreneceksin. Japonya’da kısa ve nazik ifadeler günlük iletişimde çok önemlidir.`, vocab: [{ja: `こんにちは`, tr: `merhaba / iyi günler`, ipa: `kon-ni-çi-va`},{ja: `おはようございます`, tr: `günaydın`, ipa: `o-ha-yo-o go-za-i-mas`},{ja: `こんばんは`, tr: `iyi akşamlar`, ipa: `kon-ban-va`},{ja: `ありがとう`, tr: `teşekkürler`, ipa: `a-ri-ga-to-o`},{ja: `ありがとうございます`, tr: `çok teşekkür ederim`, ipa: `a-ri-ga-to-o go-za-i-mas`},{ja: `すみません`, tr: `affedersiniz / pardon`, ipa: `su-mi-ma-sen`},{ja: `はい`, tr: `evet`, ipa: `hay`},{ja: `いいえ`, tr: `hayır`, ipa: `ii-e`},{ja: `さようなら`, tr: `hoşça kal`, ipa: `sa-yo-o-na-ra`},{ja: `またね`, tr: `görüşürüz`, ipa: `ma-ta ne`}], phrases: [{ja: `こんにちは。`, tr: `Merhaba.`, ipa: `kon-ni-çi-va`},{ja: `ありがとうございます。`, tr: `Çok teşekkür ederim.`, ipa: `a-ri-ga-to-o go-za-i-mas`},{ja: `すみません。`, tr: `Affedersiniz.`, ipa: `su-mi-ma-sen`},{ja: `はい、お願いします。`, tr: `Evet, lütfen.`, ipa: `hay, o-ne-gay-şi-mas`},{ja: `いいえ、大丈夫です。`, tr: `Hayır, sorun değil.`, ipa: `ii-e, day-coo-bu des`},{ja: `またね。`, tr: `Görüşürüz.`, ipa: `ma-ta ne`}], grammar: `Japoncada nezaket seviyesi çok önemlidir. ありがとう günlük ve samimi bir teşekkürken, ありがとうございます daha kibar ve seyahat sırasında daha güvenlidir. Cümlelerin sonunda sıkça kullanılan です ifadesi, cümleyi daha nazik yapar.`, practice: [`Bir otel görevlisine Japonca “Merhaba” de.`,`Birine kibarca teşekkür et.`,`Kalabalık bir istasyonda birinin dikkatini çekmek için “Affedersiniz” de.`,`“Evet, lütfen” ifadesini Japonca söyle.`,`“Hayır, sorun değil” cümlesini ezberden yaz.`]},{day: 2, title: `Kendini Tanıtma`, title_native: `自己紹介`, focus: `Kyoto’da bir pansiyona giriş yaparken veya yerel biriyle tanışırken adını ve nereli olduğunu söylemeyi öğreneceksin. Basit tanışma cümleleri yolculuk boyunca çok işe yarar.`, vocab: [{ja: `私`, tr: `ben`, ipa: `va-ta-şi`},{ja: `名前`, tr: `isim`, ipa: `na-ma-e`},{ja: `トルコ`, tr: `Türkiye`, ipa: `to-ru-ko`},{ja: `日本`, tr: `Japonya`, ipa: `ni-hon`},{ja: `人`, tr: `kişi / insan`, ipa: `cin`},{ja: `学生`, tr: `öğrenci`, ipa: `gak-sey`},{ja: `旅行者`, tr: `gezgin / turist`, ipa: `ryo-ko-o-şa`},{ja: `よろしくお願いします`, tr: `memnun oldum / lütfen iyi davranın`, ipa: `yo-ro-şi-ku o-ne-gay-şi-mas`},{ja: `です`, tr: `-dır / -im`, ipa: `des`},{ja: `から`, tr: `-den / -dan`, ipa: `ka-ra`}], phrases: [{ja: `私はアリです。`, tr: `Ben Ali’yim.`, ipa: `va-ta-şi va a-ri des`},{ja: `私の名前はアイリンです。`, tr: `Benim adım Aylin.`, ipa: `va-ta-şi no na-ma-e va ay-rin des`},{ja: `トルコから来ました。`, tr: `Türkiye’den geldim.`, ipa: `to-ru-ko ka-ra ki-ma-şi-ta`},{ja: `私は旅行者です。`, tr: `Ben turistim.`, ipa: `va-ta-şi va ryo-ko-o-şa des`},{ja: `よろしくお願いします。`, tr: `Memnun oldum.`, ipa: `yo-ro-şi-ku o-ne-gay-şi-mas`},{ja: `あなたの名前は何ですか。`, tr: `Adınız nedir?`, ipa: `a-na-ta no na-ma-e va nan des ka`}], grammar: `Japoncada “ben” demek için 私 kullanılır, ama konuşmada çoğu zaman bağlam belliyse özne atlanır. は parçacığı “konu”yu gösterir ve Türkçedeki “-e gelince” gibi düşünülebilir. 私はアリです cümlesi kelime kelime “Bana gelince, Ali’yim” gibi çalışır.`, practice: [`Kendi adını kullanarak “Ben ...’im” cümlesi kur.`,`Türkiye’den geldiğini Japonca söyle.`,`Birine adını kibarca sor.`,`“Ben turistim” cümlesini sesli tekrar et.`,`Yeni tanıştığın birine “Memnun oldum” de.`]},{day: 3, title: `Sayılar ve Fiyatlar`, title_native: `数字と値段`, focus: `Osaka’da markette veya otomatlarda fiyatları anlamak için temel sayıları öğreneceksin. Japonya’da nakit ve küçük alışverişler hâlâ yaygın olduğu için sayılar çok pratiktir.`, vocab: [{ja: `一`, tr: `bir`, ipa: `i-çi`},{ja: `二`, tr: `iki`, ipa: `ni`},{ja: `三`, tr: `üç`, ipa: `san`},{ja: `四`, tr: `dört`, ipa: `yon`},{ja: `五`, tr: `beş`, ipa: `go`},{ja: `六`, tr: `altı`, ipa: `ro-ku`},{ja: `七`, tr: `yedi`, ipa: `na-na`},{ja: `八`, tr: `sekiz`, ipa: `ha-çi`},{ja: `九`, tr: `dokuz`, ipa: `kyuu`},{ja: `十`, tr: `on`, ipa: `cuu`},{ja: `百`, tr: `yüz`, ipa: `hyaku`},{ja: `円`, tr: `yen`, ipa: `en`}], phrases: [{ja: `これはいくらですか。`, tr: `Bu ne kadar?`, ipa: `ko-re va i-ku-ra des ka`},{ja: `百円です。`, tr: `100 yen.`, ipa: `hya-ku en des`},{ja: `二つください。`, tr: `İki tane lütfen.`, ipa: `fu-ta-tsu ku-da-sa-i`},{ja: `一つお願いします。`, tr: `Bir tane lütfen.`, ipa: `hi-to-tsu o-ne-gay-şi-mas`},{ja: `高いです。`, tr: `Pahalı.`, ipa: `ta-ka-i des`},{ja: `安いです。`, tr: `Ucuz.`, ipa: `ya-su-i des`}], grammar: `Japoncada nesneleri sayarken genel sayaç olarak つ kullanılır: 一つ bir tane, 二つ iki tane. Bu, küçük alışverişlerde güvenli ve doğal bir kullanımdır. Fiyat sorarken これはいくらですか kalıbı neredeyse her yerde kullanılabilir.`, practice: [`1’den 10’a kadar Japonca say.`,`Bir dükkânda “Bu ne kadar?” diye sor.`,`“İki tane lütfen” cümlesini kur.`,`100 yen ve 500 yen ifadelerini söyle.`,`Pahalı ve ucuz kelimelerini karşılaştırmalı tekrar et.`]},{day: 4, title: `Evet, Hayır ve Anlamadım`, title_native: `はい、いいえ、わかりません`, focus: `Fukuoka’da günlük konuşmalarda basit cevaplar vermeyi ve anlamadığını nazikçe söylemeyi öğreneceksin. Bu ifadeler yanlış anlaşılmaları azaltır.`, vocab: [{ja: `わかります`, tr: `anlıyorum`, ipa: `va-ka-ri-mas`},{ja: `わかりません`, tr: `anlamıyorum`, ipa: `va-ka-ri-ma-sen`},{ja: `大丈夫`, tr: `sorun yok / iyi`, ipa: `day-coo-bu`},{ja: `少し`, tr: `biraz`, ipa: `su-ko-şi`},{ja: `日本語`, tr: `Japonca`, ipa: `ni-hon-go`},{ja: `英語`, tr: `İngilizce`, ipa: `ey-go`},{ja: `話します`, tr: `konuşurum`, ipa: `ha-na-şi-mas`},{ja: `ゆっくり`, tr: `yavaşça`, ipa: `yuk-ku-ri`},{ja: `もう一度`, tr: `bir kez daha`, ipa: `mo-o i-çi-do`},{ja: `お願いします`, tr: `lütfen`, ipa: `o-ne-gay-şi-mas`}], phrases: [{ja: `わかりません。`, tr: `Anlamıyorum.`, ipa: `va-ka-ri-ma-sen`},{ja: `少しわかります。`, tr: `Biraz anlıyorum.`, ipa: `su-ko-şi va-ka-ri-mas`},{ja: `日本語は少しだけです。`, tr: `Japoncam sadece biraz.`, ipa: `ni-hon-go va su-ko-şi da-ke des`},{ja: `ゆっくりお願いします。`, tr: `Yavaşça lütfen.`, ipa: `yuk-ku-ri o-ne-gay-şi-mas`},{ja: `もう一度お願いします。`, tr: `Bir kez daha lütfen.`, ipa: `mo-o i-çi-do o-ne-gay-şi-mas`},{ja: `大丈夫です。`, tr: `Sorun yok.`, ipa: `day-coo-bu des`}], grammar: `Japoncada olumsuz yapmak için birçok fiilde -ません kullanılır. わかります “anlıyorum”, わかりません “anlamıyorum” demektir. Kibar konuşmada -ます ve -ません formları seyahat için en güvenli seçimdir.`, practice: [`“Anlamıyorum” cümlesini üç kez sesli söyle.`,`Birine yavaş konuşmasını rica et.`,`“Bir kez daha lütfen” ifadesini yaz.`,`“Japoncam biraz” cümlesini ezberle.`,`“Sorun yok” ifadesini günlük bir durumda kullan.`]},{day: 5, title: `Yönler ve Basit Konumlar`, title_native: `方向と場所`, focus: `Tokyo istasyonunda veya Kyoto sokaklarında yön sormak için temel yer ve yön kelimelerini öğreneceksin. Japon şehirlerinde istasyon çıkışları ve sokaklar karmaşık olabilir.`, vocab: [{ja: `どこ`, tr: `nerede`, ipa: `do-ko`},{ja: `ここ`, tr: `burası`, ipa: `ko-ko`},{ja: `そこ`, tr: `orası`, ipa: `so-ko`},{ja: `あそこ`, tr: `şurası / orası`, ipa: `a-so-ko`},{ja: `右`, tr: `sağ`, ipa: `mi-gi`},{ja: `左`, tr: `sol`, ipa: `hi-da-ri`},{ja: `前`, tr: `ön`, ipa: `ma-e`},{ja: `後ろ`, tr: `arka`, ipa: `u-şi-ro`},{ja: `近い`, tr: `yakın`, ipa: `çi-ka-i`},{ja: `遠い`, tr: `uzak`, ipa: `to-o-i`}], phrases: [{ja: `駅はどこですか。`, tr: `İstasyon nerede?`, ipa: `e-ki va do-ko des ka`},{ja: `ここはどこですか。`, tr: `Burası neresi?`, ipa: `ko-ko va do-ko des ka`},{ja: `右です。`, tr: `Sağda.`, ipa: `mi-gi des`},{ja: `左に行ってください。`, tr: `Sola gidin lütfen.`, ipa: `hi-da-ri ni it-te ku-da-sa-i`},{ja: `近いですか。`, tr: `Yakın mı?`, ipa: `çi-ka-i des ka`},{ja: `遠いですか。`, tr: `Uzak mı?`, ipa: `to-o-i des ka`}], grammar: `どこですか kalıbı “nerede?” sorusu için kullanılır. Yer veya nesne adından sonra はどこですか ekleyerek kolayca soru kurabilirsin: トイレはどこですか “Tuvalet nerede?” gibi. に parçacığı yön ve hedef gösterebilir.`, practice: [`“İstasyon nerede?” diye Japonca sor.`,`Sağ ve sol kelimelerini işaret ederek tekrar et.`,`“Yakın mı?” ve “Uzak mı?” sorularını karşılaştır.`,`Biri sana yön tarif ederken “Anlamıyorum” demeyi dene.`,`Haritada bir yer seçip Japonca “... nerede?” sorusu kur.`]},{day: 6, title: `Tren ve Metro Kullanımı`, title_native: `電車と地下鉄`, focus: `Tokyo metrosunda bilet almak, hat sormak ve doğru trene binmek için gerekli ifadeleri öğreneceksin. Japonya’da tren sistemi çok gelişmiş ama ilk kez gelenler için karmaşık olabilir.`, vocab: [{ja: `電車`, tr: `tren`, ipa: `den-şa`},{ja: `地下鉄`, tr: `metro`, ipa: `çi-ka-te-tsu`},{ja: `駅`, tr: `istasyon`, ipa: `e-ki`},{ja: `切符`, tr: `bilet`, ipa: `kip-pu`},{ja: `ホーム`, tr: `peron`, ipa: `ho-o-mu`},{ja: `出口`, tr: `çıkış`, ipa: `de-gu-çi`},{ja: `入口`, tr: `giriş`, ipa: `i-ri-gu-çi`},{ja: `線`, tr: `hat`, ipa: `sen`},{ja: `次`, tr: `sonraki`, ipa: `tsu-gi`},{ja: `乗ります`, tr: `binerim`, ipa: `no-ri-mas`}], phrases: [{ja: `切符をください。`, tr: `Bilet lütfen.`, ipa: `kip-pu o ku-da-sa-i`},{ja: `東京駅までお願いします。`, tr: `Tokyo İstasyonu’na kadar lütfen.`, ipa: `to-o-kyo-o e-ki ma-de o-ne-gay-şi-mas`},{ja: `この電車は渋谷に行きますか。`, tr: `Bu tren Shibuya’ya gider mi?`, ipa: `ko-no den-şa va şi-bu-ya ni i-ki-mas ka`},{ja: `出口はどこですか。`, tr: `Çıkış nerede?`, ipa: `de-gu-çi va do-ko des ka`},{ja: `次の駅は何ですか。`, tr: `Sonraki istasyon ne?`, ipa: `tsu-gi no e-ki va nan des ka`},{ja: `何番ホームですか。`, tr: `Kaç numaralı peron?`, ipa: `nan-ban ho-o-mu des ka`}], grammar: `Japoncada “-e kadar” anlamı için まで kullanılır. 東京駅まで “Tokyo İstasyonu’na kadar” demektir. Gideceğin yeri söyleyip までお願いします dediğinde bilet veya taksi gibi durumlarda çok kullanışlı bir kalıp kurmuş olursun.`, practice: [`Gideceğin istasyon adını kullanarak “... kadar lütfen” de.`,`“Bu tren Shibuya’ya gider mi?” cümlesini değiştirerek başka bir yerle kullan.`,`Giriş ve çıkış kelimelerini ayırt et.`,`“Kaç numaralı peron?” sorusunu sesli tekrar et.`,`Metroda kaybolduğunu hayal edip üç yardım cümlesi kur.`]},{day: 7, title: `Tuvalet, Yardım ve Acil Temel İhtiyaçlar`, title_native: `トイレ、助け、基本の必要`, focus: `Nagoya’da alışveriş merkezi, istasyon veya park gibi yerlerde temel ihtiyaçları sormayı öğreneceksin. Seyahatte basit ihtiyaçları hızlıca ifade edebilmek çok önemlidir.`, vocab: [{ja: `トイレ`, tr: `tuvalet`, ipa: `to-i-re`},{ja: `水`, tr: `su`, ipa: `mi-zu`},{ja: `助け`, tr: `yardım`, ipa: `ta-su-ke`},{ja: `病院`, tr: `hastane`, ipa: `byo-o-in`},{ja: `警察`, tr: `polis`, ipa: `key-sa-tsu`},{ja: `電話`, tr: `telefon`, ipa: `den-va`},{ja: `充電`, tr: `şarj`, ipa: `juu-den`},{ja: `薬`, tr: `ilaç`, ipa: `ku-su-ri`},{ja: `必要`, tr: `gerekli`, ipa: `hi-tsu-yo-o`},{ja: `困っています`, tr: `zor durumdayım`, ipa: `ko-mat-te i-mas`}], phrases: [{ja: `トイレはどこですか。`, tr: `Tuvalet nerede?`, ipa: `to-i-re va do-ko des ka`},{ja: `水をください。`, tr: `Su lütfen.`, ipa: `mi-zu o ku-da-sa-i`},{ja: `助けてください。`, tr: `Lütfen yardım edin.`, ipa: `ta-su-ke-te ku-da-sa-i`},{ja: `病院はどこですか。`, tr: `Hastane nerede?`, ipa: `byo-o-in va do-ko des ka`},{ja: `電話を使ってもいいですか。`, tr: `Telefonu kullanabilir miyim?`, ipa: `den-va o tsu-kat-te mo ii des ka`},{ja: `困っています。`, tr: `Zor durumdayım.`, ipa: `ko-mat-te i-mas`}], grammar: `ください “lütfen verin / lütfen yapın” anlamında çok pratik bir kelimedir. Nesne + をください kalıbı “... lütfen” demektir: 水をください “Su lütfen.” Fiil te-formu + ください ise rica anlamı verir: 助けてください “Yardım edin lütfen.”`, practice: [`“Tuvalet nerede?” cümlesini ezberle.`,`“Su lütfen” ifadesini hızlıca söyle.`,`Acil durumda “Yardım edin lütfen” de.`,`“Zor durumdayım” cümlesini yaz.`,`Telefon kullanma izni istemeyi dene.`]},{day: 8, title: `Kafede Sipariş Verme`, title_native: `カフェで注文`, focus: `Tokyo’da küçük bir kafede kahve, çay veya atıştırmalık sipariş etmeyi öğreneceksin. Japonya’da kasada kısa ve net sipariş vermek yaygındır.`, vocab: [{ja: `コーヒー`, tr: `kahve`, ipa: `ko-o-hii`},{ja: `お茶`, tr: `çay`, ipa: `o-ça`},{ja: `水`, tr: `su`, ipa: `mi-zu`},{ja: `牛乳`, tr: `süt`, ipa: `gyuu-nyuu`},{ja: `砂糖`, tr: `şeker`, ipa: `sa-to-o`},{ja: `ケーキ`, tr: `kek / pasta`, ipa: `kee-ki`},{ja: `パン`, tr: `ekmek / hamur işi`, ipa: `pan`},{ja: `一つ`, tr: `bir tane`, ipa: `hi-to-tsu`},{ja: `二つ`, tr: `iki tane`, ipa: `fu-ta-tsu`},{ja: `店内`, tr: `içeride`, ipa: `ten-nai`},{ja: `持ち帰り`, tr: `paket / al-götür`, ipa: `mo-çi-ka-e-ri`}], phrases: [{ja: `コーヒーを一つください。`, tr: `Bir kahve lütfen.`, ipa: `ko-o-hii o hi-to-tsu ku-da-sa-i`},{ja: `お茶をお願いします。`, tr: `Çay lütfen.`, ipa: `o-ça o o-ne-gay-şi-mas`},{ja: `砂糖なしでお願いします。`, tr: `Şekersiz lütfen.`, ipa: `sa-to-o na-şi de o-ne-gay-şi-mas`},{ja: `牛乳を入れてください。`, tr: `Süt ekleyin lütfen.`, ipa: `gyuu-nyuu o i-re-te ku-da-sa-i`},{ja: `店内でお願いします。`, tr: `İçeride içeceğim.`, ipa: `ten-nai de o-ne-gay-şi-mas`},{ja: `持ち帰りでお願いします。`, tr: `Paket olsun lütfen.`, ipa: `mo-çi-ka-e-ri de o-ne-gay-şi-mas`}], grammar: `なしで “olmadan” anlamına gelir. 砂糖なしで “şekersiz” demektir. Sipariş verirken ürün + を + sayı + ください kalıbı çok kullanılır: コーヒーを一つください.`, practice: [`Bir kahve siparişi ver.`,`Çayı şekersiz istediğini söyle.`,`“Paket olsun” ifadesini kullan.`,`İki kek istediğini Japonca söyle.`,`Kafede içeride oturacağını belirt.`]},{day: 9, title: `Restoranda Yemek Siparişi`, title_native: `レストランで食事を注文`, focus: `Osaka’da bir restoranda menü istemeyi, yemek sipariş etmeyi ve öneri sormayı öğreneceksin. Japon restoranlarında nazik ama kısa ifadeler çok doğaldır.`, vocab: [{ja: `レストラン`, tr: `restoran`, ipa: `re-su-to-ran`},{ja: `メニュー`, tr: `menü`, ipa: `me-nyuu`},{ja: `おすすめ`, tr: `öneri / tavsiye`, ipa: `o-su-su-me`},{ja: `ご飯`, tr: `pilav / yemek`, ipa: `go-han`},{ja: `魚`, tr: `balık`, ipa: `sa-ka-na`},{ja: `肉`, tr: `et`, ipa: `ni-ku`},{ja: `野菜`, tr: `sebze`, ipa: `ya-sa-i`},{ja: `卵`, tr: `yumurta`, ipa: `ta-ma-go`},{ja: `辛い`, tr: `acı`, ipa: `ka-ra-i`},{ja: `おいしい`, tr: `lezzetli`, ipa: `o-i-şii`}], phrases: [{ja: `メニューをください。`, tr: `Menü lütfen.`, ipa: `me-nyuu o ku-da-sa-i`},{ja: `おすすめは何ですか。`, tr: `Tavsiyeniz nedir?`, ipa: `o-su-su-me va nan des ka`},{ja: `これは辛いですか。`, tr: `Bu acı mı?`, ipa: `ko-re va ka-ra-i des ka`},{ja: `魚をお願いします。`, tr: `Balık lütfen.`, ipa: `sa-ka-na o o-ne-gay-şi-mas`},{ja: `野菜がありますか。`, tr: `Sebze var mı?`, ipa: `ya-sa-i ga a-ri-mas ka`},{ja: `とてもおいしいです。`, tr: `Çok lezzetli.`, ipa: `to-te-mo o-i-şii des`}], grammar: `あります cansız nesneler ve mevcut olan şeyler için “var” anlamında kullanılır. 野菜がありますか “Sebze var mı?” demektir. İnsanlar ve hayvanlar için genellikle います kullanılır, ama restoran menüsü sorarken あります çok işine yarar.`, practice: [`Menü iste.`,`Garsona “Tavsiyeniz nedir?” diye sor.`,`Bir yemeğin acı olup olmadığını sor.`,`“Çok lezzetli” cümlesini yemek sonrası söyle.`,`Sebze olup olmadığını soran bir cümle kur.`]},{day: 10, title: `Diyet, Alerji ve Tercihler`, title_native: `食事制限とアレルギー`, focus: `Kyoto’da restoranda alerji veya beslenme tercihini açıklamayı öğreneceksin. Seyahatte güvenli yemek yiyebilmek için bu ifadeler çok önemlidir.`, vocab: [{ja: `アレルギー`, tr: `alerji`, ipa: `a-re-ru-gii`},{ja: `肉`, tr: `et`, ipa: `ni-ku`},{ja: `豚肉`, tr: `domuz eti`, ipa: `bu-ta-ni-ku`},{ja: `鶏肉`, tr: `tavuk eti`, ipa: `to-ri-ni-ku`},{ja: `牛肉`, tr: `dana eti`, ipa: `gyuu-ni-ku`},{ja: `魚`, tr: `balık`, ipa: `sa-ka-na`},{ja: `乳製品`, tr: `süt ürünü`, ipa: `nyuu-sey-hin`},{ja: `卵`, tr: `yumurta`, ipa: `ta-ma-go`},{ja: `食べられません`, tr: `yiyemem`, ipa: `ta-be-ra-re-ma-sen`},{ja: `入っています`, tr: `içinde var`, ipa: `ha-it-te i-mas`}], phrases: [{ja: `アレルギーがあります。`, tr: `Alerjim var.`, ipa: `a-re-ru-gii ga a-ri-mas`},{ja: `卵は食べられません。`, tr: `Yumurta yiyemem.`, ipa: `ta-ma-go va ta-be-ra-re-ma-sen`},{ja: `豚肉は入っていますか。`, tr: `İçinde domuz eti var mı?`, ipa: `bu-ta-ni-ku va ha-it-te i-mas ka`},{ja: `肉なしでお願いします。`, tr: `Etsiz lütfen.`, ipa: `ni-ku na-şi de o-ne-gay-şi-mas`},{ja: `これは大丈夫ですか。`, tr: `Bu uygun mu?`, ipa: `ko-re va day-coo-bu des ka`},{ja: `別のものはありますか。`, tr: `Başka bir şey var mı?`, ipa: `be-tsu no mo-no va a-ri-mas ka`}], grammar: `食べられません “yiyemem” anlamına gelir ve hem fiziksel hem de tercih/diyet nedeniyle kullanılabilir. Xは食べられません kalıbı, seyahatte alerji veya dini/kişisel tercih belirtmek için güvenli bir ifadedir. İçerik sormak için 入っていますか kullanılır.`, practice: [`Kendi yemediğin bir şeyi kullanarak “... yiyemem” de.`,`Bir yemekte domuz eti olup olmadığını sor.`,`“Alerjim var” cümlesini ezberle.`,`“Etsiz lütfen” ifadesini siparişte kullan.`,`“Başka bir şey var mı?” cümlesini yaz.`]},{day: 11, title: `Otelde Giriş İşlemleri`, title_native: `ホテルのチェックイン`, focus: `Sapporo’da otele giriş yaparken rezervasyon, pasaport ve oda ile ilgili temel ifadeleri öğreneceksin. Resepsiyonda nazik ve net konuşmak işleri kolaylaştırır.`, vocab: [{ja: `ホテル`, tr: `otel`, ipa: `ho-te-ru`},{ja: `予約`, tr: `rezervasyon`, ipa: `yo-ya-ku`},{ja: `チェックイン`, tr: `giriş işlemi`, ipa: `çek-ku-in`},{ja: `パスポート`, tr: `pasaport`, ipa: `pa-su-po-o-to`},{ja: `部屋`, tr: `oda`, ipa: `he-ya`},{ja: `鍵`, tr: `anahtar`, ipa: `ka-gi`},{ja: `名前`, tr: `isim`, ipa: `na-ma-e`},{ja: `一泊`, tr: `bir gece`, ipa: `ip-pa-ku`},{ja: `二泊`, tr: `iki gece`, ipa: `ni-ha-ku`},{ja: `お願いします`, tr: `lütfen`, ipa: `o-ne-gay-şi-mas`}], phrases: [{ja: `予約があります。`, tr: `Rezervasyonum var.`, ipa: `yo-ya-ku ga a-ri-mas`},{ja: `チェックインをお願いします。`, tr: `Giriş yapmak istiyorum.`, ipa: `çek-ku-in o o-ne-gay-şi-mas`},{ja: `名前はアイリンです。`, tr: `Adım Aylin.`, ipa: `na-ma-e va ay-rin des`},{ja: `パスポートです。`, tr: `Pasaportum burada.`, ipa: `pa-su-po-o-to des`},{ja: `部屋は何階ですか。`, tr: `Oda kaçıncı katta?`, ipa: `he-ya va nan-gai des ka`},{ja: `鍵をください。`, tr: `Anahtar lütfen.`, ipa: `ka-gi o ku-da-sa-i`}], grammar: `あります “var” anlamındadır ve rezervasyon gibi şeyler için kullanılır. 予約があります cümlesi “Rezervasyonum var” demenin en kullanışlı yoludur. Otel gibi resmi ortamlarda お願いします kullanmak daha nazik hissettirir.`, practice: [`“Rezervasyonum var” cümlesini söyle.`,`Kendi adını kullanarak resepsiyona adını bildir.`,`“Giriş yapmak istiyorum” ifadesini tekrar et.`,`Odanın kaçıncı katta olduğunu sor.`,`Pasaportunu verirken kullanacağın kısa cümleyi yaz.`]},{day: 12, title: `Otel Sorunları ve Talepler`, title_native: `ホテルでの問題とお願い`, focus: `Hiroshima’da otelde internet, klima veya oda sorunlarını nazikçe bildirmeyi öğreneceksin. Sorunu kısa ve açık söylemek genellikle hızlı çözüm sağlar.`, vocab: [{ja: `問題`, tr: `sorun`, ipa: `mon-dai`},{ja: `エアコン`, tr: `klima`, ipa: `e-a-kon`},{ja: `Wi-Fi`, tr: `Wi-Fi`, ipa: `vay-fay`},{ja: `暑い`, tr: `sıcak`, ipa: `a-tsu-i`},{ja: `寒い`, tr: `soğuk`, ipa: `sa-mu-i`},{ja: `壊れています`, tr: `bozuk`, ipa: `ko-va-re-te i-mas`},{ja: `使えません`, tr: `kullanamıyorum`, ipa: `tsu-ka-e-ma-sen`},{ja: `タオル`, tr: `havlu`, ipa: `ta-o-ru`},{ja: `静か`, tr: `sessiz`, ipa: `şi-zu-ka`},{ja: `部屋を変える`, tr: `odayı değiştirmek`, ipa: `he-ya o ka-e-ru`}], phrases: [{ja: `Wi-Fiが使えません。`, tr: `Wi-Fi kullanamıyorum.`, ipa: `vay-fay ga tsu-ka-e-ma-sen`},{ja: `エアコンが壊れています。`, tr: `Klima bozuk.`, ipa: `e-a-kon ga ko-va-re-te i-mas`},{ja: `部屋が寒いです。`, tr: `Oda soğuk.`, ipa: `he-ya ga sa-mu-i des`},{ja: `タオルをください。`, tr: `Havlu lütfen.`, ipa: `ta-o-ru o ku-da-sa-i`},{ja: `静かな部屋はありますか。`, tr: `Sessiz bir oda var mı?`, ipa: `şi-zu-ka na he-ya va a-ri-mas ka`},{ja: `部屋を変えたいです。`, tr: `Odayı değiştirmek istiyorum.`, ipa: `he-ya o ka-e-ta-i des`}], grammar: `たいです “istemek” anlamı verir. Fiilin köküne たいです eklenir: 変えたいです “değiştirmek istiyorum.” Seyahatte talep bildirirken bu yapı çok işe yarar ve doğrudan ama kibar bir tondadır.`, practice: [`Wi-Fi kullanamadığını söyle.`,`Klimanın bozuk olduğunu bildir.`,`“Havlu lütfen” cümlesini kur.`,`Odanın çok soğuk veya sıcak olduğunu söyle.`,`Sessiz bir oda olup olmadığını sor.`]},{day: 13, title: `Alışverişte Temel İfadeler`, title_native: `買い物の基本表現`, focus: `Tokyo’da hediyelik eşya veya kıyafet alırken fiyat, beden ve renk sormayı öğreneceksin. Japon mağazalarında nazik soru sormak iyi karşılanır.`, vocab: [{ja: `店`, tr: `mağaza`, ipa: `mi-se`},{ja: `これ`, tr: `bu`, ipa: `ko-re`},{ja: `それ`, tr: `şu / o`, ipa: `so-re`},{ja: `あれ`, tr: `o / şuradaki`, ipa: `a-re`},{ja: `値段`, tr: `fiyat`, ipa: `ne-dan`},{ja: `サイズ`, tr: `beden / boyut`, ipa: `sa-i-zu`},{ja: `色`, tr: `renk`, ipa: `i-ro`},{ja: `赤`, tr: `kırmızı`, ipa: `a-ka`},{ja: `青`, tr: `mavi`, ipa: `a-o`},{ja: `黒`, tr: `siyah`, ipa: `ku-ro`},{ja: `白`, tr: `beyaz`, ipa: `şi-ro`}], phrases: [{ja: `これはいくらですか。`, tr: `Bu ne kadar?`, ipa: `ko-re va i-ku-ra des ka`},{ja: `このサイズはありますか。`, tr: `Bu bedeni var mı?`, ipa: `ko-no sa-i-zu va a-ri-mas ka`},{ja: `黒はありますか。`, tr: `Siyahı var mı?`, ipa: `ku-ro va a-ri-mas ka`},{ja: `見てもいいですか。`, tr: `Bakabilir miyim?`, ipa: `mi-te mo ii des ka`},{ja: `これをください。`, tr: `Bunu alayım lütfen.`, ipa: `ko-re o ku-da-sa-i`},{ja: `少し考えます。`, tr: `Biraz düşüneceğim.`, ipa: `su-ko-şi ka-ga-e-mas`}], grammar: `これ, それ, あれ nesnelerin konuşana göre konumunu gösterir. これ konuşanın yanındaki, それ dinleyenin yanındaki, あれ ikinizden de uzaktaki şeydir. Alışverişte işaret ederek これをください demek çok pratiktir.`, practice: [`Yakındaki bir nesne için “Bu ne kadar?” diye sor.`,`Siyah renk olup olmadığını sor.`,`“Bakabilir miyim?” cümlesini kullan.`,`Beğendiğin bir şeyi “Bunu alayım” diye belirt.`,`Karar vermeden önce “Biraz düşüneceğim” de.`]},{day: 14, title: `Ödeme ve Kasada Konuşma`, title_native: `支払いとレジ`, focus: `Osaka’da kasada nakit, kart ve fiş gibi ödeme ifadelerini öğreneceksin. Japonya’da hâlâ nakit kullanımı yaygındır, ama kart da birçok yerde kabul edilir.`, vocab: [{ja: `レジ`, tr: `kasa`, ipa: `re-ci`},{ja: `支払い`, tr: `ödeme`, ipa: `şi-ha-ra-i`},{ja: `現金`, tr: `nakit`, ipa: `gen-kin`},{ja: `カード`, tr: `kart`, ipa: `kaa-do`},{ja: `領収書`, tr: `fiş / makbuz`, ipa: `ryo-o-şuu-şo`},{ja: `袋`, tr: `poşet`, ipa: `fu-ku-ro`},{ja: `要ります`, tr: `gerekir / lazım`, ipa: `i-ri-mas`},{ja: `要りません`, tr: `gerekmez`, ipa: `i-ri-ma-sen`},{ja: `合計`, tr: `toplam`, ipa: `go-o-key`},{ja: `払います`, tr: `öderim`, ipa: `ha-ra-i-mas`}], phrases: [{ja: `カードで払います。`, tr: `Kartla ödeyeceğim.`, ipa: `kaa-do de ha-ra-i-mas`},{ja: `現金でお願いします。`, tr: `Nakit lütfen.`, ipa: `gen-kin de o-ne-gay-şi-mas`},{ja: `袋は要りません。`, tr: `Poşet gerekmez.`, ipa: `fu-ku-ro va i-ri-ma-sen`},{ja: `領収書をください。`, tr: `Fiş lütfen.`, ipa: `ryo-o-şuu-şo o ku-da-sa-i`},{ja: `合計はいくらですか。`, tr: `Toplam ne kadar?`, ipa: `go-o-key va i-ku-ra des ka`},{ja: `ここで払いますか。`, tr: `Burada mı ödeyeceğim?`, ipa: `ko-ko de ha-ra-i-mas ka`}], grammar: `で parçacığı araç veya yöntem belirtir. カードで “kartla”, 現金で “nakitle” demektir. Ödeme sırasında yöntem + でお願いします kalıbı kısa ve kibar bir seçenektir.`, practice: [`Kartla ödeyeceğini söyle.`,`Poşet istemediğini belirt.`,`Fiş iste.`,`Toplam fiyatı sor.`,`Nakit ödeme yapacağını söyle.`]},{day: 15, title: `Saat ve Günlük Program`, title_native: `時間と予定`, focus: `Kyoto’da müze, restoran veya tren saatlerini anlamak için zaman ifadelerini öğreneceksin. Saat sormak ve program yapmak seyahatte kritik beceridir.`, vocab: [{ja: `時間`, tr: `zaman / saat`, ipa: `ci-kan`},{ja: `今`, tr: `şimdi`, ipa: `i-ma`},{ja: `何時`, tr: `saat kaç`, ipa: `nan-ci`},{ja: `一時`, tr: `saat bir`, ipa: `i-çi-ci`},{ja: `二時`, tr: `saat iki`, ipa: `ni-ci`},{ja: `半`, tr: `buçuk`, ipa: `han`},{ja: `朝`, tr: `sabah`, ipa: `a-sa`},{ja: `昼`, tr: `öğle`, ipa: `hi-ru`},{ja: `夜`, tr: `gece`, ipa: `yo-ru`},{ja: `今日`, tr: `bugün`, ipa: `kyo-o`},{ja: `明日`, tr: `yarın`, ipa: `a-şi-ta`}], phrases: [{ja: `今何時ですか。`, tr: `Şu an saat kaç?`, ipa: `i-ma nan-ci des ka`},{ja: `一時です。`, tr: `Saat bir.`, ipa: `i-çi-ci des`},{ja: `二時半です。`, tr: `Saat iki buçuk.`, ipa: `ni-ci han des`},{ja: `今日は忙しいです。`, tr: `Bugün meşgulüm.`, ipa: `kyo-o va i-so-ga-şii des`},{ja: `明日行きます。`, tr: `Yarın gideceğim.`, ipa: `a-şi-ta i-ki-mas`},{ja: `何時に開きますか。`, tr: `Saat kaçta açılıyor?`, ipa: `nan-ci ni a-ki-mas ka`}], grammar: `Saat belirtirken に parçacığı kullanılır: 二時に “saat ikide.” Soru sormak için 何時に “saat kaçta” ifadesi çok kullanışlıdır. Açılmak için 開きます, kapanmak için 閉まります fiilleri kullanılır.`, practice: [`“Şu an saat kaç?” diye sor.`,`“Saat iki buçuk” ifadesini söyle.`,`“Yarın gideceğim” cümlesini kur.`,`Bir müzenin saat kaçta açıldığını sor.`,`Bugün meşgul olduğunu belirt.`]},{day: 16, title: `Günler ve Rezervasyon`, title_native: `曜日と予約`, focus: `Tokyo’da restoran, müze veya tur için rezervasyon yapmayı ve günleri söylemeyi öğreneceksin. Planlı seyahatlerde gün ve saat ifadeleri çok işe yarar.`, vocab: [{ja: `月曜日`, tr: `pazartesi`, ipa: `ge-tsu-yo-o-bi`},{ja: `火曜日`, tr: `salı`, ipa: `ka-yo-o-bi`},{ja: `水曜日`, tr: `çarşamba`, ipa: `sui-yo-o-bi`},{ja: `木曜日`, tr: `perşembe`, ipa: `mo-ku-yo-o-bi`},{ja: `金曜日`, tr: `cuma`, ipa: `kin-yo-o-bi`},{ja: `土曜日`, tr: `cumartesi`, ipa: `do-yo-o-bi`},{ja: `日曜日`, tr: `pazar`, ipa: `ni-çi-yo-o-bi`},{ja: `予約`, tr: `rezervasyon`, ipa: `yo-ya-ku`},{ja: `空いています`, tr: `müsait / açık`, ipa: `a-i-te i-mas`},{ja: `満席`, tr: `tamamen dolu`, ipa: `man-se-ki`}], phrases: [{ja: `予約したいです。`, tr: `Rezervasyon yapmak istiyorum.`, ipa: `yo-ya-ku şi-ta-i des`},{ja: `金曜日は空いていますか。`, tr: `Cuma müsait mi?`, ipa: `kin-yo-o-bi va a-i-te i-mas ka`},{ja: `二人です。`, tr: `İki kişiyiz.`, ipa: `fu-ta-ri des`},{ja: `七時にお願いします。`, tr: `Saat yedide lütfen.`, ipa: `şi-çi-ci ni o-ne-gay-şi-mas`},{ja: `満席ですか。`, tr: `Tamamen dolu mu?`, ipa: `man-se-ki des ka`},{ja: `名前はカンです。`, tr: `İsim Kan.`, ipa: `na-ma-e va kan des`}], grammar: `Japoncada gün adlarının çoğu 曜日 ile biter. Rezervasyon yaparken kişi sayısı çok önemlidir: 一人です “bir kişiyim”, 二人です “iki kişiyiz.” Saat + に + お願いします kalıbı rezervasyonda kullanışlıdır.`, practice: [`Haftanın günlerini sırayla oku.`,`“Rezervasyon yapmak istiyorum” de.`,`İki kişilik rezervasyon istediğini söyle.`,`Cuma gününün müsait olup olmadığını sor.`,`Saat yedide rezervasyon istemeyi dene.`]},{day: 17, title: `Taksi ve Yolculuk`, title_native: `タクシーと移動`, focus: `Yokohama’da taksiye binerken varış yerini söylemeyi, ücret sormayı ve durmasını istemeyi öğreneceksin. Kısa adres ifadeleri takside yeterli olabilir.`, vocab: [{ja: `タクシー`, tr: `taksi`, ipa: `ta-ku-şii`},{ja: `住所`, tr: `adres`, ipa: `juu-şo`},{ja: `ここ`, tr: `burası`, ipa: `ko-ko`},{ja: `そこ`, tr: `orası`, ipa: `so-ko`},{ja: `ホテル`, tr: `otel`, ipa: `ho-te-ru`},{ja: `駅`, tr: `istasyon`, ipa: `e-ki`},{ja: `空港`, tr: `havalimanı`, ipa: `kuu-ko-o`},{ja: `まっすぐ`, tr: `dümdüz`, ipa: `mas-su-gu`},{ja: `止まってください`, tr: `durun lütfen`, ipa: `to-mat-te ku-da-sa-i`},{ja: `いくら`, tr: `ne kadar`, ipa: `i-ku-ra`}], phrases: [{ja: `この住所までお願いします。`, tr: `Bu adrese kadar lütfen.`, ipa: `ko-no juu-şo ma-de o-ne-gay-şi-mas`},{ja: `ホテルまでお願いします。`, tr: `Otele kadar lütfen.`, ipa: `ho-te-ru ma-de o-ne-gay-şi-mas`},{ja: `駅までいくらですか。`, tr: `İstasyona ne kadar?`, ipa: `e-ki ma-de i-ku-ra des ka`},{ja: `ここで止まってください。`, tr: `Burada durun lütfen.`, ipa: `ko-ko de to-mat-te ku-da-sa-i`},{ja: `まっすぐ行ってください。`, tr: `Dümdüz gidin lütfen.`, ipa: `mas-su-gu it-te ku-da-sa-i`},{ja: `カードは使えますか。`, tr: `Kart kullanabilir miyim?`, ipa: `kaa-do va tsu-ka-e-mas ka`}], grammar: `まで hedefin son noktasını gösterir: ホテルまで “otele kadar.” Takside bu kalıp çok yaygındır. ここで ise “burada” anlamına gelir ve durma gibi eylemlerle kullanılır.`, practice: [`Taksiye “Bu adrese kadar lütfen” de.`,`Otele kadar gitmek istediğini söyle.`,`Ücreti sormak için bir cümle kur.`,`“Burada durun lütfen” ifadesini tekrar et.`,`Kart kullanılıp kullanılamayacağını sor.`]},{day: 18, title: `Yol Tarifi Alma`, title_native: `道案内を聞く`, focus: `Kyoto’da tapınak, müze veya istasyon ararken yol tarifi sormayı ve temel cevapları anlamayı öğreneceksin. Harita uygulaması olsa bile yerel yardım çok işe yarar.`, vocab: [{ja: `道`, tr: `yol`, ipa: `mi-çi`},{ja: `地図`, tr: `harita`, ipa: `chi-zu`},{ja: `近く`, tr: `yakınlarda`, ipa: `çi-ka-ku`},{ja: `まっすぐ`, tr: `düz`, ipa: `mas-su-gu`},{ja: `曲がります`, tr: `döner`, ipa: `ma-ga-ri-mas`},{ja: `信号`, tr: `trafik ışığı`, ipa: `şin-go-o`},{ja: `角`, tr: `köşe`, ipa: `ka-do`},{ja: `橋`, tr: `köprü`, ipa: `ha-şi`},{ja: `寺`, tr: `tapınak`, ipa: `te-ra`},{ja: `神社`, tr: `Şinto tapınağı`, ipa: `cin-ca`}], phrases: [{ja: `この道でいいですか。`, tr: `Bu yol doğru mu?`, ipa: `ko-no mi-çi de ii des ka`},{ja: `寺は近くですか。`, tr: `Tapınak yakında mı?`, ipa: `te-ra va çi-ka-ku des ka`},{ja: `信号を右に曲がってください。`, tr: `Trafik ışığından sağa dönün.`, ipa: `şin-go-o o mi-gi ni ma-gat-te ku-da-sa-i`},{ja: `角を左に曲がります。`, tr: `Köşeden sola dönülür.`, ipa: `ka-do o hi-da-ri ni ma-ga-ri-mas`},{ja: `地図を見てもいいですか。`, tr: `Haritaya bakabilir miyim?`, ipa: `chi-zu o mi-te mo ii des ka`},{ja: `歩いて何分ですか。`, tr: `Yürüyerek kaç dakika?`, ipa: `a-ru-i-te nan-pun des ka`}], grammar: `Japoncada “sağa/sola dönmek” için 右に曲がります ve 左に曲がります kullanılır. を parçacığı bazen geçilen noktayı belirtir: 信号を右に曲がる “trafik ışığından sağa dönmek.” Yol tariflerinde kısa emir/rica olarak 曲がってください duyabilirsin.`, practice: [`“Bu yol doğru mu?” diye sor.`,`Bir tapınağın yakında olup olmadığını sor.`,`“Trafik ışığından sağa dönün” cümlesini anlamaya çalış.`,`Yürüyerek kaç dakika olduğunu sor.`,`Haritaya bakmak için izin iste.`]},{day: 19, title: `Müze, Tapınak ve Turistik Yerler`, title_native: `博物館、寺、観光地`, focus: `Nara’da tapınak ve müze ziyaretlerinde bilet, fotoğraf ve kurallarla ilgili ifadeleri öğreneceksin. Kültürel alanlarda nazik soru sormak çok önemlidir.`, vocab: [{ja: `博物館`, tr: `müze`, ipa: `ha-ku-bu-tsu-kan`},{ja: `美術館`, tr: `sanat müzesi`, ipa: `bi-cu-tsu-kan`},{ja: `寺`, tr: `tapınak`, ipa: `te-ra`},{ja: `神社`, tr: `Şinto tapınağı`, ipa: `cin-ca`},{ja: `入場券`, tr: `giriş bileti`, ipa: `nyuu-co-o-ken`},{ja: `写真`, tr: `fotoğraf`, ipa: `şa-şin`},{ja: `禁止`, tr: `yasak`, ipa: `kin-şi`},{ja: `中`, tr: `iç`, ipa: `na-ka`},{ja: `外`, tr: `dış`, ipa: `so-to`},{ja: `静かに`, tr: `sessizce`, ipa: `şi-zu-ka ni`}], phrases: [{ja: `入場券を一枚ください。`, tr: `Bir giriş bileti lütfen.`, ipa: `nyuu-co-o-ken o i-çi-mai ku-da-sa-i`},{ja: `写真を撮ってもいいですか。`, tr: `Fotoğraf çekebilir miyim?`, ipa: `şa-şin o tot-te mo ii des ka`},{ja: `ここは写真禁止ですか。`, tr: `Burada fotoğraf yasak mı?`, ipa: `ko-ko va şa-şin kin-şi des ka`},{ja: `中に入ってもいいですか。`, tr: `İçeri girebilir miyim?`, ipa: `na-ka ni hait-te mo ii des ka`},{ja: `静かにしてください。`, tr: `Lütfen sessiz olun.`, ipa: `şi-zu-ka ni şi-te ku-da-sa-i`},{ja: `何時に閉まりますか。`, tr: `Saat kaçta kapanıyor?`, ipa: `nan-ci ni şi-ma-ri-mas ka`}], grammar: `てもいいですか izin istemek için kullanılır. 写真を撮ってもいいですか “Fotoğraf çekebilir miyim?” demektir. Bu yapı müze, tapınak ve mağaza gibi yerlerde çok nazik ve kullanışlıdır.`, practice: [`Bir giriş bileti iste.`,`Fotoğraf çekme izni sor.`,`Fotoğrafın yasak olup olmadığını sor.`,`İçeri girebilir miyim cümlesini söyle.`,`Bir yerin saat kaçta kapandığını sor.`]},{day: 20, title: `Hava Durumu ve Kıyafetler`, title_native: `天気と服`, focus: `Sapporo veya Tokyo’da hava durumunu konuşmayı ve basit kıyafet ihtiyaçlarını ifade etmeyi öğreneceksin. Japonya’da mevsimler belirgin olduğu için hava kelimeleri pratikte çok kullanılır.`, vocab: [{ja: `天気`, tr: `hava durumu`, ipa: `ten-ki`},{ja: `雨`, tr: `yağmur`, ipa: `a-me`},{ja: `雪`, tr: `kar`, ipa: `yu-ki`},{ja: `風`, tr: `rüzgâr`, ipa: `ka-ze`},{ja: `暑い`, tr: `sıcak`, ipa: `a-tsu-i`},{ja: `寒い`, tr: `soğuk`, ipa: `sa-mu-i`},{ja: `傘`, tr: `şemsiye`, ipa: `ka-sa`},{ja: `上着`, tr: `ceket`, ipa: `u-va-gi`},{ja: `靴`, tr: `ayakkabı`, ipa: `ku-tsu`},{ja: `今日`, tr: `bugün`, ipa: `kyo-o`}], phrases: [{ja: `今日は暑いです。`, tr: `Bugün hava sıcak.`, ipa: `kyo-o va a-tsu-i des`},{ja: `今日は寒いです。`, tr: `Bugün hava soğuk.`, ipa: `kyo-o va sa-mu-i des`},{ja: `雨が降っています。`, tr: `Yağmur yağıyor.`, ipa: `a-me ga fut-te i-mas`},{ja: `傘が必要です。`, tr: `Şemsiye gerekli.`, ipa: `ka-sa ga hi-tsu-yo-o des`},{ja: `雪は降りますか。`, tr: `Kar yağacak mı?`, ipa: `yu-ki va fu-ri-mas ka`},{ja: `上着を買いたいです。`, tr: `Ceket almak istiyorum.`, ipa: `u-va-gi o ka-i-ta-i des`}], grammar: `が parçacığı hava olaylarında sık kullanılır: 雨が降っています “Yağmur yağıyor.” 降ります hem yağmur hem kar için kullanılabilir. Şu anda olan bir durumu anlatırken -ています yapısı kullanılır.`, practice: [`Bugün havanın sıcak olduğunu söyle.`,`Yağmur yağdığını belirt.`,`Şemsiye gerektiğini söyle.`,`Kar yağıp yağmayacağını sor.`,`Ceket almak istediğini ifade et.`]},{day: 21, title: `Eczane ve Sağlık`, title_native: `薬局と健康`, focus: `Tokyo’da eczaneye gidip baş ağrısı, mide sorunu veya soğuk algınlığı gibi basit sağlık durumlarını anlatmayı öğreneceksin. Seyahat sırasında sağlık ifadeleri güven verir.`, vocab: [{ja: `薬局`, tr: `eczane`, ipa: `ya-kkyo-ku`},{ja: `薬`, tr: `ilaç`, ipa: `ku-su-ri`},{ja: `頭`, tr: `baş`, ipa: `a-ta-ma`},{ja: `お腹`, tr: `karın / mide`, ipa: `o-na-ka`},{ja: `喉`, tr: `boğaz`, ipa: `no-do`},{ja: `痛い`, tr: `ağrıyor`, ipa: `i-ta-i`},{ja: `熱`, tr: `ateş`, ipa: `ne-tsu`},{ja: `風邪`, tr: `soğuk algınlığı`, ipa: `ka-ze`},{ja: `マスク`, tr: `maske`, ipa: `ma-su-ku`},{ja: `水`, tr: `su`, ipa: `mi-zu`}], phrases: [{ja: `薬局はどこですか。`, tr: `Eczane nerede?`, ipa: `ya-kkyo-ku va do-ko des ka`},{ja: `頭が痛いです。`, tr: `Başım ağrıyor.`, ipa: `a-ta-ma ga i-ta-i des`},{ja: `お腹が痛いです。`, tr: `Karnım ağrıyor.`, ipa: `o-na-ka ga i-ta-i des`},{ja: `喉が痛いです。`, tr: `Boğazım ağrıyor.`, ipa: `no-do ga i-ta-i des`},{ja: `熱があります。`, tr: `Ateşim var.`, ipa: `ne-tsu ga a-ri-mas`},{ja: `この薬はどう使いますか。`, tr: `Bu ilaç nasıl kullanılır?`, ipa: `ko-no ku-su-ri va do-o tsu-ka-i-mas ka`}], grammar: `Vücut bölgesi + が痛いです kalıbı “... ağrıyor” demektir. 頭が痛いです “Başım ağrıyor.” Ateş gibi sahip olunan durumlarda があります kullanılır: 熱があります “Ateşim var.”`, practice: [`Eczanenin nerede olduğunu sor.`,`Başının ağrıdığını söyle.`,`Karnının ağrıdığını ifade et.`,`Ateşin olduğunu söyle.`,`Bir ilacın nasıl kullanılacağını sor.`]},{day: 22, title: `Telefon, İnternet ve SIM Kart`, title_native: `電話、インターネット、SIMカード`, focus: `Narita Havalimanı veya Tokyo’da SIM kart, Wi-Fi ve telefon şarjı ile ilgili ihtiyaçları anlatmayı öğreneceksin. Bağlantı sorunları seyahat sırasında hızlı çözülmelidir.`, vocab: [{ja: `電話`, tr: `telefon`, ipa: `den-va`},{ja: `インターネット`, tr: `internet`, ipa: `in-taa-net-to`},{ja: `Wi-Fi`, tr: `Wi-Fi`, ipa: `vay-fay`},{ja: `SIMカード`, tr: `SIM kart`, ipa: `şim kaa-do`},{ja: `充電器`, tr: `şarj aleti`, ipa: `juu-den-ki`},{ja: `電池`, tr: `batarya`, ipa: `den-çi`},{ja: `使えます`, tr: `kullanabilirim`, ipa: `tsu-ka-e-mas`},{ja: `買います`, tr: `satın alırım`, ipa: `ka-i-mas`},{ja: `パスワード`, tr: `şifre`, ipa: `pa-su-waa-do`},{ja: `無料`, tr: `ücretsiz`, ipa: `mu-ryo-o`}], phrases: [{ja: `SIMカードを買いたいです。`, tr: `SIM kart almak istiyorum.`, ipa: `şim kaa-do o ka-i-ta-i des`},{ja: `Wi-Fiはありますか。`, tr: `Wi-Fi var mı?`, ipa: `vay-fay va a-ri-mas ka`},{ja: `パスワードは何ですか。`, tr: `Şifre nedir?`, ipa: `pa-su-waa-do va nan des ka`},{ja: `充電器はありますか。`, tr: `Şarj aleti var mı?`, ipa: `juu-den-ki va a-ri-mas ka`},{ja: `電話を充電したいです。`, tr: `Telefonumu şarj etmek istiyorum.`, ipa: `den-va o juu-den şi-ta-i des`},{ja: `無料ですか。`, tr: `Ücretsiz mi?`, ipa: `mu-ryo-o des ka`}], grammar: `買いたいです “satın almak istiyorum” demektir. Fiil kökü + たいです kişisel istek ifade eder. Seyahatte bu yapıyla çok şey söyleyebilirsin: 食べたいです “yemek istiyorum”, 行きたいです “gitmek istiyorum.”`, practice: [`SIM kart almak istediğini söyle.`,`Wi-Fi olup olmadığını sor.`,`Şifreyi sor.`,`Telefonunu şarj etmek istediğini ifade et.`,`Bir hizmetin ücretsiz olup olmadığını sor.`]},{day: 23, title: `Postane ve Kargo`, title_native: `郵便局と荷物`, focus: `Kyoto’da kartpostal göndermek veya küçük bir paketi postalamak için gerekli ifadeleri öğreneceksin. Japonya’da postane hizmetleri düzenli ve güvenilirdir.`, vocab: [{ja: `郵便局`, tr: `postane`, ipa: `yuu-bin-kyoku`},{ja: `手紙`, tr: `mektup`, ipa: `te-ga-mi`},{ja: `はがき`, tr: `kartpostal`, ipa: `ha-ga-ki`},{ja: `荷物`, tr: `paket / bagaj`, ipa: `ni-mo-tsu`},{ja: `切手`, tr: `pul`, ipa: `kit-te`},{ja: `送ります`, tr: `gönderirim`, ipa: `o-ku-ri-mas`},{ja: `住所`, tr: `adres`, ipa: `juu-şo`},{ja: `海外`, tr: `yurt dışı`, ipa: `ka-i-ga-i`},{ja: `トルコ`, tr: `Türkiye`, ipa: `to-ru-ko`},{ja: `いくら`, tr: `ne kadar`, ipa: `i-ku-ra`}], phrases: [{ja: `郵便局はどこですか。`, tr: `Postane nerede?`, ipa: `yuu-bin-kyoku va do-ko des ka`},{ja: `切手をください。`, tr: `Pul lütfen.`, ipa: `kit-te o ku-da-sa-i`},{ja: `トルコに送りたいです。`, tr: `Türkiye’ye göndermek istiyorum.`, ipa: `to-ru-ko ni o-ku-ri-ta-i des`},{ja: `この荷物を送りたいです。`, tr: `Bu paketi göndermek istiyorum.`, ipa: `ko-no ni-mo-tsu o o-ku-ri-ta-i des`},{ja: `いくらですか。`, tr: `Ne kadar?`, ipa: `i-ku-ra des ka`},{ja: `何日かかりますか。`, tr: `Kaç gün sürer?`, ipa: `nan-niçi ka-ka-ri-mas ka`}], grammar: `に parçacığı gönderme ve gitme hedefini gösterebilir. トルコに送ります “Türkiye’ye gönderirim” demektir. Süre sormak için 何日かかりますか “Kaç gün sürer?” ifadesi kullanılır.`, practice: [`Postanenin nerede olduğunu sor.`,`Pul iste.`,`Türkiye’ye bir kartpostal göndermek istediğini söyle.`,`Paketin ücretini sor.`,`Kaç gün süreceğini öğrenmeye çalış.`]},{day: 24, title: `Sosyal Konuşma ve Küçük Sohbet`, title_native: `雑談と会話`, focus: `Osaka’da yerel biriyle kısa ve nazik sohbet etmeyi öğreneceksin. Japonca küçük sohbetlerde aşırı kişisel olmadan basit sorular sormak doğaldır.`, vocab: [{ja: `どこから`, tr: `nereden`, ipa: `do-ko ka-ra`},{ja: `旅行`, tr: `seyahat`, ipa: `ryo-ko-o`},{ja: `好き`, tr: `sevmek / hoşlanmak`, ipa: `su-ki`},{ja: `日本`, tr: `Japonya`, ipa: `ni-hon`},{ja: `食べ物`, tr: `yemek`, ipa: `ta-be-mo-no`},{ja: `音楽`, tr: `müzik`, ipa: `on-ga-ku`},{ja: `映画`, tr: `film`, ipa: `e-i-ga`},{ja: `楽しい`, tr: `eğlenceli`, ipa: `ta-no-şii`},{ja: `きれい`, tr: `güzel / temiz`, ipa: `ki-rey`},{ja: `友達`, tr: `arkadaş`, ipa: `to-mo-da-çi`}], phrases: [{ja: `どこから来ましたか。`, tr: `Nereden geldiniz?`, ipa: `do-ko ka-ra ki-ma-şi-ta ka`},{ja: `トルコから来ました。`, tr: `Türkiye’den geldim.`, ipa: `to-ru-ko ka-ra ki-ma-şi-ta`},{ja: `日本は初めてです。`, tr: `Japonya’ya ilk gelişim.`, ipa: `ni-hon va ha-ji-me-te des`},{ja: `日本が好きです。`, tr: `Japonya’yı seviyorum.`, ipa: `ni-hon ga su-ki des`},{ja: `この町はきれいです。`, tr: `Bu şehir güzel.`, ipa: `ko-no ma-çi va ki-rey des`},{ja: `旅行は楽しいです。`, tr: `Seyahat eğlenceli.`, ipa: `ryo-ko-o va ta-no-şii des`}], grammar: `好きです Türkçedeki “seviyorum / hoşlanıyorum” anlamına gelir, ama Japoncada sıfat gibi davranır. 日本が好きです “Japonya’yı seviyorum” demektir. Burada が kullanımı çok yaygındır.`, practice: [`Birine nereden geldiğini sor.`,`Türkiye’den geldiğini söyle.`,`Japonya’ya ilk gelişin olduğunu ifade et.`,`Bir şehri güzel bulduğunu söyle.`,`Sevdiğin bir yemeği Japonca yapı ile anlatmayı dene.`]},{day: 25, title: `Davet, Plan ve Buluşma`, title_native: `誘い、予定、待ち合わせ`, focus: `Tokyo’da yeni tanıştığın biriyle kahve içmek, buluşma saati belirlemek veya plan yapmak için ifadeler öğreneceksin. Basit ve nazik davet cümleleri sosyal seyahatlerde işe yarar.`, vocab: [{ja: `会います`, tr: `buluşurum`, ipa: `a-i-mas`},{ja: `待ち合わせ`, tr: `buluşma`, ipa: `ma-çi-a-wa-se`},{ja: `カフェ`, tr: `kafe`, ipa: `ka-fe`},{ja: `一緒に`, tr: `birlikte`, ipa: `is-şo ni`},{ja: `行きます`, tr: `giderim`, ipa: `i-ki-mas`},{ja: `飲みます`, tr: `içerim`, ipa: `no-mi-mas`},{ja: `時間`, tr: `zaman`, ipa: `ci-kan`},{ja: `大丈夫`, tr: `uygun / sorun yok`, ipa: `day-coo-bu`},{ja: `今日`, tr: `bugün`, ipa: `kyo-o`},{ja: `明日`, tr: `yarın`, ipa: `a-şi-ta`}], phrases: [{ja: `一緒にカフェに行きませんか。`, tr: `Birlikte kafeye gitmek ister misiniz?`, ipa: `is-şo ni ka-fe ni i-ki-ma-sen ka`},{ja: `明日は大丈夫ですか。`, tr: `Yarın uygun musunuz?`, ipa: `a-şi-ta va day-coo-bu des ka`},{ja: `何時に会いますか。`, tr: `Saat kaçta buluşalım?`, ipa: `nan-ci ni a-i-mas ka`},{ja: `駅で会いましょう。`, tr: `İstasyonda buluşalım.`, ipa: `e-ki de a-i-ma-şo-o`},{ja: `コーヒーを飲みましょう。`, tr: `Kahve içelim.`, ipa: `ko-o-hii o no-mi-ma-şo-o`},{ja: `また会いたいです。`, tr: `Tekrar buluşmak istiyorum.`, ipa: `ma-ta a-i-ta-i des`}], grammar: `ませんか kibar bir davet yapısıdır. 行きませんか kelime kelime “gitmez misiniz?” gibi görünür ama doğal anlamı “gitmek ister misiniz?”dir. ましょう ise “hadi ... yapalım” anlamı verir.`, practice: [`Birini kafeye davet et.`,`Yarın uygun olup olmadığını sor.`,`Saat kaçta buluşulacağını sor.`,`İstasyonda buluşmayı öner.`,`“Tekrar buluşmak istiyorum” cümlesini söyle.`]},{day: 26, title: `Duygular ve Fikirler`, title_native: `気持ちと意見`, focus: `Japonya’da gezerken beğeni, şaşkınlık, yorgunluk ve fikirlerini basitçe anlatmayı öğreneceksin. Seyahat sohbetlerinde duyguları ifade etmek konuşmayı daha doğal yapar.`, vocab: [{ja: `嬉しい`, tr: `mutlu`, ipa: `u-re-şii`},{ja: `楽しい`, tr: `eğlenceli`, ipa: `ta-no-şii`},{ja: `疲れた`, tr: `yoruldum`, ipa: `tsu-ka-re-ta`},{ja: `眠い`, tr: `uykum var`, ipa: `ne-mu-i`},{ja: `好き`, tr: `seviyorum`, ipa: `su-ki`},{ja: `嫌い`, tr: `sevmiyorum`, ipa: `ki-ra-i`},{ja: `すごい`, tr: `harika / inanılmaz`, ipa: `su-go-i`},{ja: `きれい`, tr: `güzel`, ipa: `ki-rey`},{ja: `面白い`, tr: `ilginç / eğlenceli`, ipa: `o-mo-şi-ro-i`},{ja: `ちょっと`, tr: `biraz`, ipa: `çot-to`}], phrases: [{ja: `とても楽しいです。`, tr: `Çok eğlenceli.`, ipa: `to-te-mo ta-no-şii des`},{ja: `少し疲れました。`, tr: `Biraz yoruldum.`, ipa: `su-ko-şi tsu-ka-re-ma-şi-ta`},{ja: `これはすごいです。`, tr: `Bu harika.`, ipa: `ko-re va su-go-i des`},{ja: `この場所が好きです。`, tr: `Bu yeri seviyorum.`, ipa: `ko-no ba-şo ga su-ki des`},{ja: `ちょっと眠いです。`, tr: `Biraz uykum var.`, ipa: `çot-to ne-mu-i des`},{ja: `面白いですね。`, tr: `İlginç, değil mi?`, ipa: `o-mo-şi-ro-i des ne`}], grammar: `ね cümle sonuna geldiğinde “değil mi?” veya “öyle, değil mi?” gibi ortak duygu arar. 面白いですね “İlginç, değil mi?” gibi doğal bir ifadedir. Sohbette yumuşak ve dostça bir ton verir.`, practice: [`Çok eğlendiğini söyle.`,`Biraz yorulduğunu ifade et.`,`Bir manzara için “Bu harika” de.`,`Sevdiğin bir yeri Japonca anlat.`,`“İlginç, değil mi?” ifadesini bir sohbet cümlesinde kullan.`]},{day: 27, title: `Sorun Çözme ve Şikâyet Etme`, title_native: `問題解決と苦情`, focus: `Otel, restoran veya ulaşımda bir sorun yaşadığında nazikçe açıklama yapmayı öğreneceksin. Japon kültüründe sakin, dolaylı ve kibar ifade önemlidir.`, vocab: [{ja: `問題`, tr: `sorun`, ipa: `mon-dai`},{ja: `違います`, tr: `farklı / yanlış`, ipa: `çi-ga-i-mas`},{ja: `遅い`, tr: `geç / yavaş`, ipa: `o-so-i`},{ja: `早い`, tr: `erken / hızlı`, ipa: `ha-ya-i`},{ja: `なくしました`, tr: `kaybettim`, ipa: `na-ku-şi-ma-şi-ta`},{ja: `忘れました`, tr: `unuttum`, ipa: `va-su-re-ma-şi-ta`},{ja: `予約`, tr: `rezervasyon`, ipa: `yo-ya-ku`},{ja: `確認`, tr: `kontrol / doğrulama`, ipa: `ka-ku-nin`},{ja: `もう一度`, tr: `tekrar`, ipa: `mo-o i-çi-do`},{ja: `すみません`, tr: `özür / pardon`, ipa: `su-mi-ma-sen`}], phrases: [{ja: `予約が見つかりません。`, tr: `Rezervasyon bulunamıyor.`, ipa: `yo-ya-ku ga mi-tsu-ka-ri-ma-sen`},{ja: `これは違います。`, tr: `Bu yanlış / farklı.`, ipa: `ko-re va çi-ga-i-mas`},{ja: `財布をなくしました。`, tr: `Cüzdanımı kaybettim.`, ipa: `sa-i-fu o na-ku-şi-ma-şi-ta`},{ja: `確認してください。`, tr: `Lütfen kontrol edin.`, ipa: `ka-ku-nin şi-te ku-da-sa-i`},{ja: `もう一度お願いします。`, tr: `Tekrar lütfen.`, ipa: `mo-o i-çi-do o-ne-gay-şi-mas`},{ja: `すみません、困っています。`, tr: `Affedersiniz, zor durumdayım.`, ipa: `su-mi-ma-sen, ko-mat-te i-mas`}], grammar: `してください, isim + してください ile “lütfen ... yapın” anlamı verir. 確認してください “Lütfen kontrol edin” demektir. Sorun bildirirken önce すみません demek tonu yumuşatır.`, practice: [`Rezervasyonun bulunamadığını söyle.`,`Bir şeyin yanlış olduğunu kibarca belirt.`,`Cüzdanını kaybettiğini ifade et.`,`Kontrol etmelerini rica et.`,`“Zor durumdayım” cümlesini tekrar et.`]},{day: 28, title: `Daha Doğal Konuşma Bağlaçları`, title_native: `自然な会話のつなぎ言葉`, focus: `Tokyo’da günlük sohbeti daha akıcı yapmak için “ama”, “çünkü”, “sonra” gibi bağlayıcı ifadeleri öğreneceksin. Bu kelimeler kısa cümleleri daha doğal hale getirir.`, vocab: [{ja: `でも`, tr: `ama`, ipa: `de-mo`},{ja: `そして`, tr: `ve sonra / ayrıca`, ipa: `so-şi-te`},{ja: `だから`, tr: `bu yüzden`, ipa: `da-ka-ra`},{ja: `それから`, tr: `ondan sonra`, ipa: `so-re-ka-ra`},{ja: `たぶん`, tr: `belki`, ipa: `ta-bun`},{ja: `本当に`, tr: `gerçekten`, ipa: `hon-to-o ni`},{ja: `もちろん`, tr: `elbette`, ipa: `mo-çi-ron`},{ja: `まだ`, tr: `henüz / hâlâ`, ipa: `ma-da`},{ja: `もう`, tr: `artık / çoktan`, ipa: `mo-o`},{ja: `少し`, tr: `biraz`, ipa: `su-ko-şi`}], phrases: [{ja: `でも、高いです。`, tr: `Ama pahalı.`, ipa: `de-mo, ta-ka-i des`},{ja: `そして、駅に行きます。`, tr: `Sonra istasyona gideceğim.`, ipa: `so-şi-te, e-ki ni i-ki-mas`},{ja: `だから、タクシーに乗ります。`, tr: `Bu yüzden taksiye bineceğim.`, ipa: `da-ka-ra, ta-ku-şii ni no-ri-mas`},{ja: `たぶん大丈夫です。`, tr: `Belki sorun olmaz.`, ipa: `ta-bun day-coo-bu des`},{ja: `本当においしいです。`, tr: `Gerçekten lezzetli.`, ipa: `hon-to-o ni o-i-şii des`},{ja: `もちろん行きます。`, tr: `Elbette gideceğim.`, ipa: `mo-çi-ron i-ki-mas`}], grammar: `Bağlaçlar Japoncada genellikle cümlenin başında kullanılır ve konuşmayı daha doğal yapar. でも “ama”, だから “bu yüzden” demektir. Kısa cümleleri bağlayarak daha uzun ama hâlâ anlaşılır konuşmalar kurabilirsin.`, practice: [`“Ama pahalı” cümlesini söyle.`,`Bir planı “sonra” bağlacıyla anlat.`,`“Bu yüzden taksiye bineceğim” cümlesini kur.`,`“Belki sorun olmaz” ifadesini kullan.`,`Gerçekten lezzetli bulduğun bir şey için cümle kur.`]},{day: 29, title: `Geçmiş Zamanla Seyahat Anlatma`, title_native: `過去形で旅行を話す`, focus: `Japonya gezinin sonunda nereye gittiğini, ne yediğini ve neleri sevdiğini anlatmayı öğreneceksin. Geçmiş zaman kısa sohbetlerde çok işe yarar.`, vocab: [{ja: `行きました`, tr: `gittim`, ipa: `i-ki-ma-şi-ta`},{ja: `食べました`, tr: `yedim`, ipa: `ta-be-ma-şi-ta`},{ja: `飲みました`, tr: `içtim`, ipa: `no-mi-ma-şi-ta`},{ja: `見ました`, tr: `gördüm / izledim`, ipa: `mi-ma-şi-ta`},{ja: `買いました`, tr: `satın aldım`, ipa: `ka-i-ma-şi-ta`},{ja: `楽しかった`, tr: `eğlenceliydi`, ipa: `ta-no-şi-kat-ta`},{ja: `おいしかった`, tr: `lezzetliydi`, ipa: `o-i-şi-kat-ta`},{ja: `昨日`, tr: `dün`, ipa: `ki-no-o`},{ja: `先週`, tr: `geçen hafta`, ipa: `sen-şuu`},{ja: `旅行`, tr: `seyahat`, ipa: `ryo-ko-o`}], phrases: [{ja: `昨日、京都に行きました。`, tr: `Dün Kyoto’ya gittim.`, ipa: `ki-no-o, kyo-o-to ni i-ki-ma-şi-ta`},{ja: `寿司を食べました。`, tr: `Suşi yedim.`, ipa: `su-şi o ta-be-ma-şi-ta`},{ja: `お茶を飲みました。`, tr: `Çay içtim.`, ipa: `o-ça o no-mi-ma-şi-ta`},{ja: `寺を見ました。`, tr: `Tapınağı gördüm.`, ipa: `te-ra o mi-ma-şi-ta`},{ja: `とても楽しかったです。`, tr: `Çok eğlenceliydi.`, ipa: `to-te-mo ta-no-şi-kat-ta des`},{ja: `おいしかったです。`, tr: `Lezzetliydi.`, ipa: `o-i-şi-kat-ta des`}], grammar: `Kibar geçmiş zaman için fiillerde -ました kullanılır: 行きます “giderim”, 行きました “gittim.” İ-sıfatlarda geçmiş için sonundaki い düşer ve かった eklenir: おいしい → おいしかった. Kibar yapmak için sonuna です eklenebilir.`, practice: [`Dün nereye gittiğini Japonca söyle.`,`Yediğin bir yemeği geçmiş zamanda anlat.`,`“Çok eğlenceliydi” cümlesini kur.`,`Bir tapınağı gördüğünü söyle.`,`“Lezzetliydi” ifadesini yemek sonrası kullan.`]},{day: 30, title: `Yolculuğu Tamamlama ve Vedalaşma`, title_native: `旅の終わりと別れ`, focus: `Havalimanına giderken, otelden ayrılırken veya yeni arkadaşlarınla vedalaşırken kullanacağın son ifadeleri öğreneceksin. Bu gün, önceki derslerdeki temel yapıları bir araya getirir.`, vocab: [{ja: `空港`, tr: `havalimanı`, ipa: `kuu-ko-o`},{ja: `出発`, tr: `kalkış / ayrılış`, ipa: `şup-pa-tsu`},{ja: `到着`, tr: `varış`, ipa: `to-o-ça-ku`},{ja: `荷物`, tr: `bagaj`, ipa: `ni-mo-tsu`},{ja: `忘れ物`, tr: `unutulan eşya`, ipa: `va-su-re-mo-no`},{ja: `ありがとう`, tr: `teşekkürler`, ipa: `a-ri-ga-to-o`},{ja: `また`, tr: `tekrar`, ipa: `ma-ta`},{ja: `会います`, tr: `buluşurum`, ipa: `a-i-mas`},{ja: `気をつけて`, tr: `dikkat et / iyi yolculuklar`, ipa: `ki o tsu-ke-te`},{ja: `さようなら`, tr: `hoşça kal`, ipa: `sa-yo-o-na-ra`}], phrases: [{ja: `チェックアウトをお願いします。`, tr: `Çıkış yapmak istiyorum.`, ipa: `çek-ku-a-u-to o o-ne-gay-şi-mas`},{ja: `空港までお願いします。`, tr: `Havalimanına kadar lütfen.`, ipa: `kuu-ko-o ma-de o-ne-gay-şi-mas`},{ja: `荷物をお願いします。`, tr: `Bagajımı lütfen.`, ipa: `ni-mo-tsu o o-ne-gay-şi-mas`},{ja: `忘れ物はありませんか。`, tr: `Unutulan eşya var mı?`, ipa: `va-su-re-mo-no va a-ri-ma-sen ka`},{ja: `本当にありがとうございました。`, tr: `Gerçekten çok teşekkür ederim.`, ipa: `hon-to-o ni a-ri-ga-to-o go-za-i-ma-şi-ta`},{ja: `また会いましょう。`, tr: `Tekrar görüşelim.`, ipa: `ma-ta a-i-ma-şo-o`}], grammar: `ありがとうございました geçmişe dönük teşekkür etmek için kullanılır; bir hizmet tamamlandıktan sonra çok doğaldır. また会いましょう “tekrar görüşelim” demektir ve vedalaşırken sıcak bir kapanış sağlar. Seyahat sonunda kibar geçmiş ifadeler iyi bir izlenim bırakır.`, practice: [`Otelden çıkış yapmak istediğini söyle.`,`Havalimanına gitmek istediğini taksiye bildir.`,`Gerçekten teşekkür ettiğini ifade et.`,`Unutulan eşya olup olmadığını sor.`,`“Tekrar görüşelim” cümlesini vedalaşmada kullan.`]}];

var CONVERSATIONS_TR_JA = [{id: 1, title: `Kafede Kahve Siparişi`, scene: `Tokyo’da küçük bir kafeye girdin. Kasiyer hızlı konuşuyor ama sen basit ve kibar ifadelerle sipariş vermek istiyorsun.`, lines: [{who: `them`, ja: `いらっしゃいませ。`, tr: `Hoş geldiniz.`},{who: `you`, ja: `こんにちは。コーヒーを一つください。`, tr: `Merhaba. Bir kahve lütfen.`},{who: `them`, ja: `店内ですか、持ち帰りですか。`, tr: `İçeride mi, paket mi?`},{who: `you`, ja: `店内でお願いします。`, tr: `İçeride lütfen.`},{who: `them`, ja: `砂糖と牛乳は要りますか。`, tr: `Şeker ve süt ister misiniz?`},{who: `you`, ja: `砂糖なしで、牛乳をお願いします。`, tr: `Şekersiz, süt lütfen.`},{who: `them`, ja: `ケーキもいかがですか。`, tr: `Kek de ister misiniz?`},{who: `you`, ja: `いいえ、大丈夫です。`, tr: `Hayır, sorun değil.`},{who: `them`, ja: `合計で四百円です。`, tr: `Toplam 400 yen.`},{who: `you`, ja: `カードで払います。`, tr: `Kartla ödeyeceğim.`},{who: `them`, ja: `ありがとうございます。`, tr: `Teşekkür ederiz.`},{who: `you`, ja: `ありがとうございます。`, tr: `Teşekkür ederim.`}]},{id: 2, title: `Otelde Check-in`, scene: `Kyoto’da oteline vardın ve resepsiyonda giriş yapmak istiyorsun. Rezervasyonun var ve pasaportunu göstermen gerekiyor.`, lines: [{who: `them`, ja: `こんばんは。チェックインですか。`, tr: `İyi akşamlar. Giriş işlemi mi?`},{who: `you`, ja: `はい、チェックインをお願いします。`, tr: `Evet, giriş yapmak istiyorum.`},{who: `them`, ja: `お名前をお願いします。`, tr: `İsminizi alabilir miyim?`},{who: `you`, ja: `名前はカンです。予約があります。`, tr: `İsim Kan. Rezervasyonum var.`},{who: `them`, ja: `パスポートをお願いします。`, tr: `Pasaportunuzu alabilir miyim?`},{who: `you`, ja: `はい、パスポートです。`, tr: `Evet, pasaportum burada.`},{who: `them`, ja: `二泊ですね。`, tr: `İki gece, doğru mu?`},{who: `you`, ja: `はい、二泊です。`, tr: `Evet, iki gece.`},{who: `them`, ja: `部屋は五階です。`, tr: `Odanız beşinci katta.`},{who: `you`, ja: `鍵をください。`, tr: `Anahtar lütfen.`},{who: `them`, ja: `こちらです。`, tr: `Buyurun.`},{who: `you`, ja: `ありがとうございます。`, tr: `Teşekkür ederim.`}]},{id: 3, title: `Yol Tarifi Sorma`, scene: `Nara’da bir tapınağa gitmek istiyorsun ama sokaklar karışık. Yoldan geçen birine nazikçe soruyorsun.`, lines: [{who: `you`, ja: `すみません。寺はどこですか。`, tr: `Affedersiniz. Tapınak nerede?`},{who: `them`, ja: `この道をまっすぐ行ってください。`, tr: `Bu yoldan dümdüz gidin.`},{who: `you`, ja: `まっすぐですね。`, tr: `Dümdüz, değil mi?`},{who: `them`, ja: `はい、信号を右に曲がってください。`, tr: `Evet, trafik ışığından sağa dönün.`},{who: `you`, ja: `右ですね。歩いて何分ですか。`, tr: `Sağ, değil mi? Yürüyerek kaç dakika?`},{who: `them`, ja: `十分ぐらいです。`, tr: `Yaklaşık on dakika.`},{who: `you`, ja: `近いですか。`, tr: `Yakın mı?`},{who: `them`, ja: `はい、近いです。`, tr: `Evet, yakın.`},{who: `you`, ja: `地図を見てもいいですか。`, tr: `Haritaya bakabilir miyim?`},{who: `them`, ja: `もちろんです。ここです。`, tr: `Elbette. Burası.`},{who: `you`, ja: `ありがとうございます。`, tr: `Teşekkür ederim.`},{who: `them`, ja: `気をつけて。`, tr: `Dikkatli gidin.`}]},{id: 4, title: `Restoranda Akşam Yemeği`, scene: `Osaka’da bir restorandasın ve garsondan öneri istiyorsun. Acı yemekten kaçınmak istiyorsun.`, lines: [{who: `them`, ja: `いらっしゃいませ。二人ですか。`, tr: `Hoş geldiniz. İki kişi misiniz?`},{who: `you`, ja: `はい、二人です。`, tr: `Evet, iki kişiyiz.`},{who: `them`, ja: `メニューです。`, tr: `Menü buyurun.`},{who: `you`, ja: `ありがとうございます。おすすめは何ですか。`, tr: `Teşekkür ederim. Tavsiyeniz nedir?`},{who: `them`, ja: `魚がおすすめです。`, tr: `Balığı tavsiye ederim.`},{who: `you`, ja: `これは辛いですか。`, tr: `Bu acı mı?`},{who: `them`, ja: `いいえ、辛くないです。`, tr: `Hayır, acı değil.`},{who: `you`, ja: `では、魚をお願いします。`, tr: `O zaman balık lütfen.`},{who: `them`, ja: `飲み物はどうしますか。`, tr: `İçecek ne olsun?`},{who: `you`, ja: `お茶をお願いします。`, tr: `Çay lütfen.`},{who: `them`, ja: `かしこまりました。`, tr: `Elbette.`},{who: `you`, ja: `よろしくお願いします。`, tr: `Teşekkürler / ilgilenirseniz sevinirim.`}]},{id: 5, title: `Metro Bileti Alma`, scene: `Tokyo metrosunda Shibuya’ya gitmek istiyorsun. Doğru bilet ve peronu sorman gerekiyor.`, lines: [{who: `them`, ja: `こんにちは。どこまでですか。`, tr: `Merhaba. Nereye kadar?`},{who: `you`, ja: `渋谷までお願いします。`, tr: `Shibuya’ya kadar lütfen.`},{who: `them`, ja: `切符は一枚ですか。`, tr: `Bir bilet mi?`},{who: `you`, ja: `はい、一枚ください。`, tr: `Evet, bir tane lütfen.`},{who: `them`, ja: `二百円です。`, tr: `200 yen.`},{who: `you`, ja: `カードは使えますか。`, tr: `Kart kullanabilir miyim?`},{who: `them`, ja: `はい、使えます。`, tr: `Evet, kullanabilirsiniz.`},{who: `you`, ja: `この電車は渋谷に行きますか。`, tr: `Bu tren Shibuya’ya gider mi?`},{who: `them`, ja: `はい、三番ホームです。`, tr: `Evet, üçüncü peron.`},{who: `you`, ja: `三番ホームですね。`, tr: `Üçüncü peron, değil mi?`},{who: `them`, ja: `はい、そうです。`, tr: `Evet, doğru.`},{who: `you`, ja: `ありがとうございます。`, tr: `Teşekkür ederim.`}]},{id: 6, title: `Hediyelik Eşya Alışverişi`, scene: `Kyoto’da küçük bir hediyelik eşya mağazasındasın. Bir ürünün fiyatını, rengini ve poşet gerekip gerekmediğini konuşuyorsun.`, lines: [{who: `them`, ja: `いらっしゃいませ。`, tr: `Hoş geldiniz.`},{who: `you`, ja: `こんにちは。これはいくらですか。`, tr: `Merhaba. Bu ne kadar?`},{who: `them`, ja: `これは千円です。`, tr: `Bu 1000 yen.`},{who: `you`, ja: `黒はありますか。`, tr: `Siyahı var mı?`},{who: `them`, ja: `はい、あります。`, tr: `Evet, var.`},{who: `you`, ja: `見てもいいですか。`, tr: `Bakabilir miyim?`},{who: `them`, ja: `もちろんです。`, tr: `Elbette.`},{who: `you`, ja: `これをください。`, tr: `Bunu alayım lütfen.`},{who: `them`, ja: `袋は要りますか。`, tr: `Poşet ister misiniz?`},{who: `you`, ja: `袋は要りません。`, tr: `Poşet gerekmez.`},{who: `them`, ja: `ありがとうございます。`, tr: `Teşekkür ederiz.`},{who: `you`, ja: `ありがとうございます。`, tr: `Teşekkür ederim.`}]},{id: 7, title: `Eczanede Yardım İsteme`, scene: `Tokyo’da boğazın ağrıyor ve bir eczaneye girdin. Basit şekilde şikâyetini anlatıp ilacın nasıl kullanılacağını soruyorsun.`, lines: [{who: `them`, ja: `こんにちは。どうしましたか。`, tr: `Merhaba. Ne oldu?`},{who: `you`, ja: `喉が痛いです。`, tr: `Boğazım ağrıyor.`},{who: `them`, ja: `熱はありますか。`, tr: `Ateşiniz var mı?`},{who: `you`, ja: `少し熱があります。`, tr: `Biraz ateşim var.`},{who: `them`, ja: `この薬がいいです。`, tr: `Bu ilaç iyi olur.`},{who: `you`, ja: `この薬はどう使いますか。`, tr: `Bu ilaç nasıl kullanılır?`},{who: `them`, ja: `水と一緒に飲んでください。`, tr: `Suyla birlikte için.`},{who: `you`, ja: `一日に何回ですか。`, tr: `Günde kaç kez?`},{who: `them`, ja: `一日に三回です。`, tr: `Günde üç kez.`},{who: `you`, ja: `わかりました。ありがとうございます。`, tr: `Anladım. Teşekkür ederim.`},{who: `them`, ja: `お大事に。`, tr: `Geçmiş olsun.`},{who: `you`, ja: `ありがとうございます。`, tr: `Teşekkür ederim.`}]},{id: 8, title: `Yerel Biriyle Küçük Sohbet`, scene: `Osaka’da bir parkta otururken yerel biri seninle sohbet başlatıyor. Nereden geldiğini, Japonya’yı nasıl bulduğunu ve planlarını konuşuyorsun.`, lines: [{who: `you`, ja: `こんにちは。ここはきれいですね。`, tr: `Merhaba. Burası güzel, değil mi?`},{who: `them`, ja: `こんにちは。はい、とてもきれいです。`, tr: `Merhaba. Evet, çok güzel.`},{who: `you`, ja: `私はトルコから来ました。`, tr: `Türkiye’den geldim.`},{who: `them`, ja: `そうですか。日本は初めてですか。`, tr: `Öyle mi? Japonya’ya ilk gelişiniz mi?`},{who: `you`, ja: `はい、初めてです。`, tr: `Evet, ilk kez.`},{who: `them`, ja: `日本はどうですか。`, tr: `Japonya nasıl?`},{who: `you`, ja: `とても楽しいです。食べ物もおいしいです。`, tr: `Çok eğlenceli. Yemekler de lezzetli.`},{who: `them`, ja: `今日はどこに行きますか。`, tr: `Bugün nereye gideceksiniz?`},{who: `you`, ja: `たぶん博物館に行きます。`, tr: `Belki müzeye gideceğim.`},{who: `them`, ja: `いいですね。気をつけて。`, tr: `Güzel. Dikkatli gidin.`},{who: `you`, ja: `ありがとうございます。また会いましょう。`, tr: `Teşekkür ederim. Tekrar görüşelim.`},{who: `them`, ja: `またね。`, tr: `Görüşürüz.`}]}];